## Minimum, Complete, Verifiable Example

Using my custom class with python builtin `sorted()` works 100%. But with `natsorted`, Python throws a insane type error.

```python
from natsort import natsorted

class Production(object):
    def __init__(self, arg):
        self.arg = arg

    def __str__(self):
        return self.arg

    def __lt__(self, other):
        return str( self ) < str( other )

    def __hash__(self):
        return hash( str( self ) )

    def __iter__(self):
        self.__dict__['index'] = True
        return self

    def __next__(self):

        if self.index:
            self.__dict__['index'] = False
            return self.arg

        raise StopIteration


class Terminal(object):
    def __init__(self, arg):
        self.arg = arg

    def __str__(self):
        return self.arg

    def __lt__(self, other):
        return str( self ) < str( other )

    def __hash__(self):
        return hash( str( self ) )


terminal = Terminal('B')
production = Production('A')

trouble_set = [terminal, production]

print( 'Python    sorted:', sorted( trouble_set ) )
print(  )
print( 'natsorted sorted:', natsorted( trouble_set ) )

```


## Error message, Traceback, Desired behavior, Suggestion, Request, or Question

```
