}

double optimize() {
  nlopt::opt opt(nlopt::LN_NELDERMEAD, 1);
  opt.set_lower_bounds(std::vector<double>{0});
  opt.set_upper_bounds(std::vector<double>{1});
  opt.set_maxeval(100);
  opt.set_xtol_rel(0.01);
  opt.set_max_objective(func, NULL);
